using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using TRANSFER_IN_PLAN.Data;
using TRANSFER_IN_PLAN.Models;

namespace TRANSFER_IN_PLAN.Controllers;

public class WeekCalendarController : Controller
{
    private readonly PlanningDbContext _context;
        private readonly ILogger<WeekCalendarController> _logger;

            public WeekCalendarController(PlanningDbContext context, ILogger<WeekCalendarController> logger)
                {
                        _context = context;
                                _logger = logger;
                                    }

                                        // GET: WeekCalendar
                                            public async Task<IActionResult> Index()
                                                {
                                                        try
                                                                {
                                                                            _logger.LogInformation("Loading WeekCalendar list.");
                                                                                        var weekCalendars = await _context.WeekCalendars.OrderBy(w => w.WeekId).ToListAsync();
                                                                                                    return View(weekCalendars);
                                                                                                            }
                                                                                                                    catch (Exception ex)
                                                                                                                            {
                                                                                                                                        _logger.LogError(ex, "Error loading WeekCalendar list.");
                                                                                                                                                    ViewBag.ErrorMessage = "Error loading data: " + ex.Message;
                                                                                                                                                                return View(new List<WeekCalendar>());
                                                                                                                                                                        }
                                                                                                                                                                            }
                                                                                                                                                                            
                                                                                                                                                                                // GET: WeekCalendar/Create
                                                                                                                                                                                    public IActionResult Create()
                                                                                                                                                                                        {
                                                                                                                                                                                                return View();
                                                                                                                                                                                                    }
                                                                                                                                                                                                    
                                                                                                                                                                                                        // POST: WeekCalendar/Create
                                                                                                                                                                                                            [HttpPost]
                                                                                                                                                                                                                [ValidateAntiForgeryToken]
                                                                                                                                                                                                                    public async Task<IActionResult> Create([Bind("WeekId,WeekSeq,FyWeek,FyYear,CalYear,YearWeek,WkStDt,WkEndDt")] WeekCalendar weekCalendar)
                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                if (ModelState.IsValid)
                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                                    try
                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                _context.Add(weekCalendar);
                                                                                                                                                                                                                                                                                                await _context.SaveChangesAsync();
                                                                                                                                                                                                                                                                                                                _logger.LogInformation("WeekCalendar created: WeekId={WeekId}", weekCalendar.WeekId);
                                                                                                                                                                                                                                                                                                                                TempData["SuccessMessage"] = $"Week {weekCalendar.YearWeek} created successfully.";
                                                                                                                                                                                                                                                                                                                                                return RedirectToAction(nameof(Index));
                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                        catch (Exception ex)
                                                                                                                                                                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                                                                                                                                                                                    _logger.LogError(ex, "Error creating WeekCalendar WeekId={WeekId}", weekCalendar.WeekId);
                                                                                                                                                                                                                                                                                                                                                                                                                    ModelState.AddModelError("", "Error saving record: " + ex.Message);
                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                return View(weekCalendar);
                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                        // GET: WeekCalendar/Edit/5
                                                                                                                                                                                                                                                                                                                                                                                                                                                            public async Task<IActionResult> Edit(int? id)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (id == null) return NotFound();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                var weekCalendar = await _context.WeekCalendars.FindAsync(id);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (weekCalendar == null) return NotFound();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                return View(weekCalendar);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // POST: WeekCalendar/Edit/5
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            [HttpPost]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                [ValidateAntiForgeryToken]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    public async Task<IActionResult> Edit(int id, [Bind("WeekId,WeekSeq,FyWeek,FyYear,CalYear,YearWeek,WkStDt,WkEndDt")] WeekCalendar weekCalendar)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (id != weekCalendar.WeekId) return NotFound();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (ModelState.IsValid)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            try
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        _context.Update(weekCalendar);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        await _context.SaveChangesAsync();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        _logger.LogInformation("WeekCalendar updated: WeekId={WeekId}", weekCalendar.WeekId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        TempData["SuccessMessage"] = $"Week {weekCalendar.YearWeek} updated successfully.";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return RedirectToAction(nameof(Index));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                catch (DbUpdateConcurrencyException)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (!WeekCalendarExists(weekCalendar.WeekId))
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                return NotFound();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                throw;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        catch (Exception ex)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    _logger.LogError(ex, "Error updating WeekCalendar WeekId={WeekId}", weekCalendar.WeekId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ModelState.AddModelError("", "Error updating record: " + ex.Message);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                return View(weekCalendar);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // GET: WeekCalendar/Delete/5
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            public async Task<IActionResult> Delete(int? id)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (id == null) return NotFound();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                var weekCalendar = await _context.WeekCalendars.FindAsync(id);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (weekCalendar == null) return NotFound();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                return View(weekCalendar);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // POST: WeekCalendar/Delete/5
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            [HttpPost, ActionName("Delete")]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                [ValidateAntiForgeryToken]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    public async Task<IActionResult> DeleteConfirmed(int id)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                try
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    var weekCalendar = await _context.WeekCalendars.FindAsync(id);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (weekCalendar != null)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            _context.WeekCalendars.Remove(weekCalendar);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            await _context.SaveChangesAsync();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            _logger.LogInformation("WeekCalendar deleted: WeekId={WeekId}", id);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            TempData["SuccessMessage"] = "Week calendar record deleted successfully.";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        catch (Exception ex)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            _logger.LogError(ex, "Error deleting WeekCalendar WeekId={WeekId}", id);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        TempData["ErrorMessage"] = "Error deleting record: " + ex.Message;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return RedirectToAction(nameof(Index));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                private bool WeekCalendarExists(int id)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            return _context.WeekCalendars.Any(e => e.WeekId == id);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
